// Helper functions for product queries
export function getProductBySlug(slug: string): Product | undefined {
  return products.find(p => p.slug === slug);
}

export function getProductById(id: string): Product | undefined {
  return products.find(p => p.id === id);
}

export function getProductsByCategory(categorySlug: string): Product[] {
  return products.filter(p => p.categorySlug === categorySlug);
}

export function getProductsBySubcategory(categorySlug: string, subcategorySlug: string): Product[] {
  return products.filter(p => p.categorySlug === categorySlug && p.subcategorySlug === subcategorySlug);
}

export function getRelatedProducts(product: Product): Product[] {
  if (!product.relatedProducts) return [];
  return product.relatedProducts
    .map(id => getProductById(id))
    .filter((p): p is Product => p !== undefined);
}

export function getProductPath(product: Product): string {
  if (product.subcategorySlug) {
    return `/${product.categorySlug}/${product.subcategorySlug}/${product.slug}/`;
  }
  return `/${product.categorySlug}/${product.slug}/`;
}
